import socket
import sys
from concurrent.futures import ThreadPoolExecutor

def scan_port(host: str, port: int) -> tuple:
    try:
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
            s.settimeout(1)
            result = s.connect_ex((host, port))
            return port, result == 0
    except:
        return port, False

def scan_ports(host: str, ports: range):
    print(f"Scanning {host}...")
    open_ports = []
    with ThreadPoolExecutor(max_workers=50) as executor:
        futures = {executor.submit(scan_port, host, p): p for p in ports}
        for future in futures:
            port, is_open = future.result()
            if is_open:
                open_ports.append(port)
                print(f"  Port {port}: OPEN")
    return sorted(open_ports)

if __name__ == "__main__":
    host = sys.argv[1] if len(sys.argv) > 1 else input("Host: ")
    open_ports = scan_ports(host, range(1, 1025))
    print(f"\nOpen ports: {open_ports}")

import os
import base64
from cryptography.fernet import Fernet
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2

class SecureCredentialStore:
    """Securely store and retrieve API keys using encryption."""

    def __init__(self, master_key: str = None):
        if master_key is None:
            master_key = os.environ.get("MASTER_KEY")
            if not master_key:
                raise ValueError("Set MASTER_KEY environment variable")
        self.cipher = self._derive_key(master_key)

    def _derive_key(self, master_key: str) -> Fernet:
        salt = b"cyber-llm-salt"  # In production, store separately
        kdf = PBKDF2(
            algorithm=hashes.SHA256(),
            length=32,
            salt=salt,
            iterations=600000,
        )
        key = base64.urlsafe_b64encode(kdf.derive(master_key.encode()))
        return Fernet(key)

    def store(self, credential: str) -> bytes:
        return self.cipher.encrypt(credential.encode())

    def retrieve(self, encrypted: bytes) -> str:
        return self.cipher.decrypt(encrypted).decode()

    @staticmethod
    def generate_master_key() -> str:
        return base64.urlsafe_b64encode(os.urandom(32)).decode()

# Usage:
# store = SecureCredentialStore()
# encrypted = store.store("sk-1234...")
# print(encrypted)  # save this to a file
# key = store.retrieve(encrypted)  # recover the API key

