#include <immintrin.h>
#include <stddef.h>

float sum_avx2(const float *restrict a, size_t n) {
    __m256 acc = _mm256_setzero_ps();
    size_t i = 0;
    for (; i + 8 <= n; i += 8)            // 8 floats per 256-bit lane
        acc = _mm256_add_ps(acc, _mm256_loadu_ps(&a[i]));
    float tail = 0.0f;                     // handle remainder scalar
    for (; i < n; i++) tail += a[i];
    __m128 lo = _mm256_castps256_ps128(acc);
    __m128 hi = _mm256_extractf128_ps(acc, 1);
    lo = _mm_add_ps(lo, hi);
    lo = _mm_hadd_ps(lo, lo); lo = _mm_hadd_ps(lo, lo);
    return _mm_cvtss_f32(lo) + tail;
}
```
Keep the hot loop branchless and aligned (`_mm256_load_ps` for 32-byte-aligned buffers), handle the scalar remainder outside the vectorized loop, and avoid `restrict`-violating aliasing.

