```cpp
#include <atomic>
#include <vector>

template <typename T>
struct SPSC {
    std::vector<T> buf; size_t cap;
    std::atomic<size_t> head{0}, tail{0};   // single writer / single reader
    bool push(const T& x) {
        size_t h = head.load(std::memory_order_relaxed);
        if (h - tail.load(std::memory_order_acquire) == cap) return false;
        buf[h & (cap-1)] = x; h++; head.store(h, std::memory_order_release); return true;
    }
};
```
With one producer and one consumer, `head`/`tail` are accessed by different threads, so no CAS is needed — plain atomic loads/stores with acquire/release ordering avoid locks and false sharing. Size the capacity to a power of two for a cheap mask.

