import dpkt
import socket
from collections import defaultdict

class DNSTunnelDetector:
    def __init__(self, threshold=50):
        self.queries = defaultdict(list)
        self.threshold = threshold

    def analyze_pcap(self, pcap_file):
        with open(pcap_file, 'rb') as f:
            pcap = dpkt.pcap.Reader(f)

            for timestamp, buf in pcap:
                try:
                    eth = dpkt.ethernet.Ethernet(buf)
                    if isinstance(eth.data, dpkt.ip.IP):
                        ip = eth.data
                        if isinstance(ip.data, dpkt.udp.UDP) and ip.data.dport == 53:
                            dns = dpkt.dns.DNS(ip.data.data)
                            self._check_query(dns, timestamp)
                except:
                    pass

    def _check_query(self, dns, timestamp):
        for q in dns.qd:
            domain = q.name.decode('utf-8', errors='ignore')
            self.queries[domain].append(timestamp)

            # Check indicators
            length = len(domain)
            entropy = self._entropy(domain)
            subdomain_count = domain.count('.')

            if (length > 50 or
                entropy > 4.0 or
                subdomain_count > 5 or
                len(self.queries) > 100):
                print(f'[ALERT] Possible DNS tunnel: {domain}')
                print(f'  Length: {length}, Entropy: {entropy:.2f}')

    def _entropy(self, s):
        import math
        prob = [float(s.count(c)) / len(s) for c in set(s)]
        return -sum(p * math.log(p) / math.log(2.0) for p in prob)

if __name__ == '__main__':
    detector = DNSTunnelDetector()
    detector.analyze_pcap('capture.pcap')

## Smart Contract Reentrancy Attack

### How It Works
Reentrancy exploits the fact that a contract can call back into the calling contract before the first invocation completes, allowing withdrawal of funds multiple times.

### Classic Example (The DAO Hack 2016 — $60M stolen)
```solidity
// VULNERABLE
contract Victim {
    mapping(address => uint) balances;

    function withdraw(uint amount) public {
        require(balances[msg.sender] >= amount);
        (bool success, ) = msg.sender.call{value: amount}("");  // calls attacker!
        require(success);
        balances[msg.sender] -= amount;  // balance NOT updated yet
    }
}

// ATTACKER
contract Attacker {
    Victim victim;

    function attack() public {
        victim.withdraw(1 ether);
    }

    receive() external payable {
        if (address(victim).balance > 0) {
            victim.withdraw(1 ether);  // re-enter before balance updated
        }
    }
}
```

### The Fix: Checks-Effects-Interactions Pattern
```solidity
// SECURE
contract Safe {
    mapping(address => uint) balances;

    function withdraw(uint amount) public {
        require(balances[msg.sender] >= amount);
        balances[msg.sender] -= amount;  // EFFECTS first
        (bool success, ) = msg.sender.call{value: amount}("");  // INTERACTION last
        require(success);
    }
}
```

### Prevention
1. **Checks-Effects-Interactions**: Update state before calling external contracts
2. **ReentrancyGuard (OpenZeppelin)**: Mutex lock
3. **Limit gas**: Send only enough for the intended operation
4. **Avoid `call.value()`**: Prefer `transfer()` (forwards 2300 gas — enough only for logging)
5. **Formal verification**: Use tools like Slither, Mythril, Certora

### Other Common Smart Contract Vulnerabilities
- **Flash loan attacks**: Oracle manipulation via uncollateralized loans
- **Front-running**: MEV bots exploit transaction ordering
- **Access control**: Missing `onlyOwner` modifiers
- **Integer overflow/underflow**: Arithmetic without SafeMath
- **Oracle manipulation**: Price feed single-source dependency

