// SECURE: Validate input, use safe APIs
func lookup(hostname string) error {
    // 1. Validate the hostname is a valid hostname/IP
    if strings.Contains(hostname, " ") ||
       strings.Contains(hostname, "|") ||
       strings.Contains(hostname, ";") ||
       strings.Contains(hostname, "$") {
        return fmt.Errorf("invalid hostname: contains shell metacharacters")
    }

    // 2. Resolve via net package instead of shelling out
    ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
    defer cancel()

    ips, err := net.DefaultResolver.LookupHost(ctx, hostname)
    if err != nil {
        return fmt.Errorf("lookup failed: %w", err)
    }

    fmt.Printf("Host %s resolves to: %v\n", hostname, ips)
    return nil
}

// If ping is genuinely needed, use exec.Command (not shell)
