                "arn:aws:s3:::artifacts-prod/ci/*",
                "arn:aws:s3:::artifacts-prod/deployments/*"
            ],
            "Condition": {
                "StringEquals": {
                    "s3:x-amz-server-side-encryption": "AES256"
                }
            }
        },
        {
            "Sid": "DenyDelete",
            "Effect": "Deny",
            "Action": [
                "s3:DeleteObject",
                "s3:DeleteObjectVersion",
                "s3:DeleteBucketPolicy"
            ],
            "Resource": "arn:aws:s3:::artifacts-prod/*"
        },
        {
            "Sid": "DenyPublicAccess",
            "Effect": "Deny",
            "Action": [
                "s3:PutBucketAcl",
                "s3:PutBucketPolicy",
                "s3:PutObjectAcl"
            ],
            "Resource": "arn:aws:s3:::artifacts-prod/*"
        }
    ]
}
```

### Policy Notes
- **Lists**: Only the specific bucket, not all buckets
- **Write**: Restricted to `ci/` and `deployments/` prefixes
- **Encryption**: Enforced via condition key
- **Deny delete**: Prevents accidental or malicious deletion
- **Deny public**: Blocks any ACL/policy changes that could expose data

